package org.apache.commons.math3.optimization.univariate.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.analysis.UnivariateFunction;
import org.apache.commons.math3.analysis.function.Sin;
import org.apache.commons.math3.analysis.function.StepFunction;
import org.apache.commons.math3.analysis.FunctionUtils;
import org.apache.commons.math3.optimization.GoalType;
import static org.junit.Assert.*;

public class StepDefs {

    private UnivariateFunction function;
    private double initialGuess;
    private double solution;
    private BrentOptimizer optimizer;
    private UnivariatePointValuePair result;

    @Given("a univariate function {string} composed of a sine wave and a step function")
    public void a_univariate_function_composed_of_a_sine_wave_and_a_step_function(String functionDescription) {
        // Create a function that combines sine wave and step function as in the test
        final double minSin = 3 * Math.PI / 2;
        final double offset = 1e-8;
        final double[] stepX = { minSin, minSin + offset, minSin + 2 * offset };
        final double[] stepY = { 0, -1, 0 };

        final UnivariateFunction f1 = new Sin();
        final UnivariateFunction f2 = new StepFunction(stepX, stepY);
        this.function = FunctionUtils.add(f1, f2);
    }

    @Given("an initial guess {string} is chosen such that {string} is the global minimum in the search interval")
    public void an_initial_guess_is_chosen_such_that_is_the_global_minimum_in_the_search_interval(String initialGuessVar, String functionAtInitialGuess) {
        // Set the initial guess to the value that represents the global minimum
        // Based on the test case, this would be minSin + 1.5 * offset
        final double minSin = 3 * Math.PI / 2;
        final double offset = 1e-8;
        this.initialGuess = minSin + 1.5 * offset;
    }

    @When("the BrentOptimizer optimizes {string} starting from {string}")
    public void the_brent_optimizer_optimizes_starting_from(String functionVar, String initialGuessVar) {
        // Create the optimizer
        this.optimizer = new BrentOptimizer(1e-8, 1e-100);

        // Define search interval
        final double minSin = 3 * Math.PI / 2;
        final double delta = 1e-7;
        final double min = minSin - 6.789 * delta;
        final double max = minSin + 9.876 * delta;

        try {
            // Perform the optimization starting from the initial guess
            this.result = optimizer.optimize(200, function, GoalType.MINIMIZE, min, max, initialGuess);
            this.solution = result.getPoint();
        } catch (Exception e) {
            throw new RuntimeException("Optimization failed: " + e.getMessage(), e);
        }
    }

    @Then("the returned solution {string} must satisfy {string} <= {string}")
    public void the_returned_solution_must_satisfy(String solutionVar, String functionAtSolution, String functionAtInitial) {
        // Check that the solution gives a value less than or equal to the initial guess
        double functionAtSol = function.value(solution);
        double functionAtInit = function.value(initialGuess);

        assertTrue("The solution should have a function value <= initial guess value, but f(solution)=" + 
                  functionAtSol + " and f(initialGuess)=" + functionAtInit, 
                  functionAtSol <= functionAtInit);
    }
}

